system(size: 11, weight: .bold))                    .foregroundColor(.secondary)            } else if case .upcoming(let time) = game.status {                Text(time)                    .font(.system(size: 11, weight: .medium))                    .foregroundColor(.secondary)            }                        if let quarter = game.quarter {                Text("• \(quarter)")                    .font(.system(size: 11, weight: .medium))                    .foregroundColor(.secondary)            }                        if let time = game.timeRemaining {                Text(time)                    .font(.system(size: 11, weight: .medium))                    .foregroundColor(.secondary)            }        }    }}struct GameCardTeams: View {    let game: Game        var body: some View {        VStack(spacing: 0) {            // Away Team            GameCardTeamRow(                teamName: game.awayTeam,                score: game.awayScore,                logoURL: game.awayLogoURL,                sport: game.sport,                isWinning: game.awayScore > game.homeScore,                isUpcoming: isUpcoming(game.status)            )                        Divider()                .padding(.horizontal, 12)                        // Home Team            GameCardTeamRow(                teamName: game.homeTeam,                score: game.homeScore,                logoURL: game.homeLogoURL,                sport: game.sport,                isWinning: game.homeScore > game.awayScore,                isUpcoming: isUpcoming(game.status)            )        }    }        private func isUpcoming(_ status: GameStatus) -> Bool {        if case .upcoming = status {            return true        }        return false    }}struct GameCardTeamRow: View {    let teamName: String    let score: Int    let logoURL: String?    let sport: Sport    let isWinning: Bool    let isUpcoming: Bool        var body: some View {        HStack(spacing: 8) {            // Team Logo            if let logoURL = logoURL, let url = URL(string: logoURL) {                AsyncImage(url: url) { image in                    image                        .resizable()                        .aspectRatio(contentMode: .fit)                } placeholder: {                    Image(systemName: sport.icon)                        .font(.system(size: 16))                        .foregroundColor(sport.color)                }                .frame(width: 24, height: 24)            } else {                Image(systemName: sport.icon)                    .font(.system(size: 16))                    .foregroundColor(sport.color)                    .frame(width: 24, height: 24)            }                        Text(teamName)                .font(.system(size: 16, weight: .medium))                        Spacer()                        if isUpcoming {                Text("-")                    .font(.system(size: 18, weight: .medium))                    .foregroundColor(.secondary)            } else {                Text("\(score)")                    .font(.system(size: 18, weight: isWinning ? .bold : .regular))                    .foregroundColor(isWinning ? .primary : .secondary)            }        }        .padding(.horizontal, 12)        .padding(.vertical, 8)    }}